mapper.select:
SELECT p.id, p.title, LEFT(regexp_replace(p.content, '<[^>]*>', '', 'g'), 100) AS summary, u.nickname AS author_nickname, u.avatar AS author_avatar, b.id AS board_id, b.name AS board_name, p.view_count, p.like_count, p.comment_count, p.is_pinned, p.is_featured, p.created_at FROM post p JOIN "user" u ON p.author_id = u.id AND u.deleted = 0 JOIN board b ON p.board_id = b.id WHERE p.deleted = 0 AND p.status = 1 AND (p.title ILIKE CONCAT('%', #{query.keyword}, '%') OR p.content ILIKE CONCAT('%', #{query.keyword}, '%'))
AND p.board_id = #{query.boardId}
ORDER BY p.created_at DESC
